  ('public-health-specialist-moex-01367', 'public-health-specialist', 'public-health-specialist-moex-111-8041b019', 'sub-public-health-specialist-04', NULL, 'single_choice', '分析年齡（age）、性別（gender）、教育程度（educ）與美國總統選舉（vote）的相關性，這些 變數的數值編碼（coding）與分析結果如下。請問男性對比女性選民（Male vs. Female），投 給Trump（vote=1vs.0）的勝算比為何？ vote 0=''Clinton'' 1=''Trump''; gender 1=''Male'' 2=''Female''; educ 1=''HSNotCompleted'' 2=''CompletedHS'' 3=''College<4Years'' 4=''College4YearDegree'' 5=''AdvancedDegree''; AnalysisofMaximumLikelihoodEstimates Standard Wald Parameter DF Estimate Error Chi-Square Pr>ChiSq Intercept 1 0.2754 0.1959 1.9759 0.1598 gender Female 1 -0.3559 0.0841 17.8915 <.0001 gender Male 0 0 - - - age 1 0.0131 0.00246 28.3128 <.0001 educ 1 -0.2518 0.0387 42.3355 <.0001', '["0.3559", "-0.3559", "e-0.3559", "e0.3559"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:59+00:00", "source_pdf_sha1": "3b26ea176416", "answer_pdf_sha1": "af1063b3ceba", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生物統計學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01368', 'public-health-specialist', 'public-health-specialist-moex-111-8041b019', 'sub-public-health-specialist-04', NULL, 'single_choice', '某個治療肺癌病人的臨床試驗比較試驗用藥（test drug）和標準治療（standardtreatment）兩 組病人的存活狀況，分析結果如圖所示，下列敘述何者錯誤？', '["此存活曲線是由Kaplan-Meier 估計值（estimates）所繪製而成", "試驗用藥（testdrug）比標準治療（standardtreatment）的存活狀況好", "試驗用藥（testdrug）的中位數存活時間在180天以上", "標準治療（standardtreatment）的中位數存活時間在150天以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:59+00:00", "source_pdf_sha1": "3b26ea176416", "answer_pdf_sha1": "af1063b3ceba", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生物統計學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01369', 'public-health-specialist', 'public-health-specialist-moex-111-8041b019', 'sub-public-health-specialist-04', NULL, 'single_choice', '在進行比較實驗組與對照組之衛教介入前後知識分數的改變量平均值時，統計分析軟體提供 了下列的結果，以0.05的型一誤差（typeIerrorrate）來判定： 檢定兩組變異數是否有差異的F檢定：p-value=0.010 Equalvariance 之t檢定：p-value=0.001 Unequalvariance 之t檢定：p-value=0.212 請問下列敘述何者正確？', '["實驗組和對照組的改變量平均值達顯著性差異，此檢定的p值是0.010", "實驗組和對照組的改變量平均值達顯著性差異，此檢定的p值是0.001", "實驗組和對照組的改變量平均值沒有達顯著性差異，此檢定的p值是0.212", "實驗組和對照組的改變量平均值沒有達顯著性差異，此檢定的p值是0.001"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:59+00:00", "source_pdf_sha1": "3b26ea176416", "answer_pdf_sha1": "af1063b3ceba", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生物統計學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01370', 'public-health-specialist', 'public-health-specialist-moex-111-8041b019', 'sub-public-health-specialist-04', NULL, 'single_choice', '在執行存活分析時需要定義每筆個案的資料之追蹤結果是屬於事件（event）資料，還是 設限（censor）資料，某一結腸直腸癌的標靶藥品治療研究，病人在試驗結束後所登錄的 追蹤結果分別是：A=存活，B=死於肺癌，C=死於結腸直腸癌，D=死於肺癌及結腸直腸 癌以外的其他癌症，E=死於非癌症的其他原因，因此在計算各種死亡率時，下列敘述何 者錯誤？', '["計算癌症存活率時，BCD設定成事件資料，AE設定成設限資料", "計算結腸直腸癌存活率時，C設定成事件資料，ABDE設定成設限資料", "計算總存活率時，BCDE設定成事件資料，A設定成設限資料", "計算肺癌存活率時，BC設定成事件資料，ADE設定成設限資料"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:59+00:00", "source_pdf_sha1": "3b26ea176416", "answer_pdf_sha1": "af1063b3ceba", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生物統計學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
